from __future__ import annotations

import ssl
import time
import typing

SOCKET_OPTION = typing.Union[
    typing.Tuple[int, int, int],
    typing.Tuple[int, int, typing.Union[bytes, bytearray]],
    typing.Tuple[int, int, None, int],
]


class NetworkStream:
    def read(self, max_bytes: int, timeout: float | None = None) -> bytes:
        """Read up to max_bytes from the stream, optionally respecting a timeout.

        Args:
            max_bytes: Maximum number of bytes to read.
            timeout: Optional timeout in seconds for the read operation.

        Returns:
            The bytes read from the stream.

        Raises:
            NotImplementedError: Implementations must provide this method.
        """
        raise NotImplementedError()  # pragma: nocover

    def write(self, buffer: bytes, timeout: float | None = None) -> None:
        """Write the given bytes to the stream, optionally respecting a timeout.

        Args:
            buffer: Bytes to write to the stream.
            timeout: Optional timeout in seconds for the write operation.

        Raises:
            NotImplementedError: Implementations must provide this method.
        """
        raise NotImplementedError()  # pragma: nocover

    def close(self) -> None:
        """Close the stream and release any associated resources.

        Raises:
            NotImplementedError: Implementations must provide this method.
        """
        raise NotImplementedError()  # pragma: nocover

    def start_tls(
        self,
        ssl_context: ssl.SSLContext,
        server_hostname: str | None = None,
        timeout: float | None = None,
    ) -> NetworkStream:
        """Upgrade the existing connection to TLS and return a TLS-wrapped stream.

        Args:
            ssl_context: The SSLContext to use for the TLS handshake.
            server_hostname: Optional server hostname for SNI.
            timeout: Optional timeout in seconds for the handshake.

        Returns:
            A NetworkStream instance representing the TLS-wrapped connection.

        Raises:
            NotImplementedError: Implementations must provide this method.
        """
        raise NotImplementedError()  # pragma: nocover

    def get_extra_info(self, info: str) -> typing.Any:
        """Return optional transport-specific information.

        Args:
            info: The name of the information to retrieve (e.g., 'peername').

        Returns:
            Transport-specific data or None if not available.
        """
        return None  # pragma: nocover


class NetworkBackend:
    def connect_tcp(
        self,
        host: str,
        port: int,
        timeout: float | None = None,
        local_address: str | None = None,
        socket_options: typing.Iterable[SOCKET_OPTION] | None = None,
    ) -> NetworkStream:
        """Open a TCP connection to the given host and port.

        Args:
            host: Remote host to connect to.
            port: Remote port to connect to.
            timeout: Optional connection timeout in seconds.
            local_address: Optional local address to bind before connecting.
            socket_options: Optional iterable of socket options to set on the socket.

        Returns:
            A NetworkStream representing the connected socket.

        Raises:
            NotImplementedError: Implementations must provide this method.
        """
        raise NotImplementedError()  # pragma: nocover

    def connect_unix_socket(
        self,
        path: str,
        timeout: float | None = None,
        socket_options: typing.Iterable[SOCKET_OPTION] | None = None,
    ) -> NetworkStream:
        """Open a connection to a Unix domain socket specified by path.

        Args:
            path: Filesystem path to the Unix socket.
            timeout: Optional connection timeout in seconds.
            socket_options: Optional iterable of socket options to set on the socket.

        Returns:
            A NetworkStream representing the connected Unix domain socket.

        Raises:
            NotImplementedError: Implementations must provide this method.
        """
        raise NotImplementedError()  # pragma: nocover

    def sleep(self, seconds: float) -> None:
        """Block the current thread for the given number of seconds.

        Args:
            seconds: Number of seconds to sleep.
        """
        time.sleep(seconds)  # pragma: nocover


class AsyncNetworkStream:
    async def read(self, max_bytes: int, timeout: float | None = None) -> bytes:
        """Asynchronously read up to max_bytes from the stream.

        Args:
            max_bytes: Maximum number of bytes to read.
            timeout: Optional timeout in seconds for the read operation.

        Returns:
            The bytes read from the stream.

        Raises:
            NotImplementedError: Implementations must provide this method.
        """
        raise NotImplementedError()  # pragma: nocover

    async def write(self, buffer: bytes, timeout: float | None = None) -> None:
        """Asynchronously write the given bytes to the stream.

        Args:
            buffer: Bytes to write to the stream.
            timeout: Optional timeout in seconds for the write operation.

        Raises:
            NotImplementedError: Implementations must provide this method.
        """
        raise NotImplementedError()  # pragma: nocover

    async def aclose(self) -> None:
        """Asynchronously close the stream and release any associated resources.

        Raises:
            NotImplementedError: Implementations must provide this method.
        """
        raise NotImplementedError()  # pragma: nocover

    async def start_tls(
        self,
        ssl_context: ssl.SSLContext,
        server_hostname: str | None = None,
        timeout: float | None = None,
    ) -> AsyncNetworkStream:
        """Asynchronously upgrade the connection to TLS and return a TLS-wrapped stream.

        Args:
            ssl_context: The SSLContext to use for the TLS handshake.
            server_hostname: Optional server hostname for SNI.
            timeout: Optional timeout in seconds for the handshake.

        Returns:
            An AsyncNetworkStream representing the TLS-wrapped connection.

        Raises:
            NotImplementedError: Implementations must provide this method.
        """
        raise NotImplementedError()  # pragma: nocover

    def get_extra_info(self, info: str) -> typing.Any:
        """Return optional transport-specific information for the async stream.

        Args:
            info: The name of the information to retrieve (e.g., 'peername').

        Returns:
            Transport-specific data or None if not available.
        """
        return None  # pragma: nocover


class AsyncNetworkBackend:
    async def connect_tcp(
        self,
        host: str,
        port: int,
        timeout: float | None = None,
        local_address: str | None = None,
        socket_options: typing.Iterable[SOCKET_OPTION] | None = None,
    ) -> AsyncNetworkStream:
        """Asynchronously open a TCP connection to the given host and port.

        Args:
            host: Remote host to connect to.
            port: Remote port to connect to.
            timeout: Optional connection timeout in seconds.
            local_address: Optional local address to bind before connecting.
            socket_options: Optional iterable of socket options to set on the socket.

        Returns:
            An AsyncNetworkStream representing the connected socket.

        Raises:
            NotImplementedError: Implementations must provide this method.
        """
        raise NotImplementedError()  # pragma: nocover

    async def connect_unix_socket(
        self,
        path: str,
        timeout: float | None = None,
        socket_options: typing.Iterable[SOCKET_OPTION] | None = None,
    ) -> AsyncNetworkStream:
        """Asynchronously open a connection to a Unix domain socket specified by path.

        Args:
            path: Filesystem path to the Unix socket.
            timeout: Optional connection timeout in seconds.
            socket_options: Optional iterable of socket options to set on the socket.

        Returns:
            An AsyncNetworkStream representing the connected Unix domain socket.

        Raises:
            NotImplementedError: Implementations must provide this method.
        """
        raise NotImplementedError()  # pragma: nocover

    async def sleep(self, seconds: float) -> None:
        """Asynchronously sleep for the given number of seconds.

        Args:
            seconds: Number of seconds to sleep.

        Raises:
            NotImplementedError: Implementations must provide this method.
        """
        raise NotImplementedError()  # pragma: nocover